window.addEventListener("load",()=>{let e=document.getElementById("body_page"),t=document.getElementById("preload");e&&e.classList.remove("overflow-preload"),t&&(t.style.display="none")});var typed=new Typed("#typed_element",{stringsElement:"#typed-strings",typeSpeed:25,backSpeed:25,startDelay:2e3,backDelay:1e3,showCursor:!0,cursorChar:"|"});const copyText=document.getElementById("contact_mail").innerHTML,copyButton=document.getElementById("copy_button"),copyMessage=document.getElementById("copy_message");copyButton.addEventListener("click",async()=>{try{await navigator.clipboard.writeText(copyText),copyMessage.innerText="Email copiado correctamente.",setTimeout(()=>{copyMessage.innerText=""},2500)}catch(e){console.error("Error al copiar: ",e)}});